CREATE TABLE IF NOT EXISTS public.community_posts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, title VARCHAR(255) NOT NULL, content TEXT NOT NULL, excerpt VARCHAR(500), category VARCHAR(50) NOT NULL DEFAULT 'tools', tags TEXT[] DEFAULT ARRAY[]::TEXT[], images TEXT[] DEFAULT ARRAY[]::TEXT[], meta JSONB DEFAULT '{}', likes_count INTEGER DEFAULT 0, comments_count INTEGER DEFAULT 0, views_count INTEGER DEFAULT 0, favorites_count INTEGER DEFAULT 0, is_pinned BOOLEAN DEFAULT FALSE, is_locked BOOLEAN DEFAULT FALSE, status VARCHAR(20) DEFAULT 'published', auto_promoted BOOLEAN DEFAULT FALSE, auto_promote_reason TEXT, promoted_to_category VARCHAR(50), promote_source VARCHAR(20), promote_score INTEGER, direct_publish_requested BOOLEAN DEFAULT FALSE, direct_publish_cost INTEGER, is_hot_boost BOOLEAN DEFAULT FALSE, hot_boost_expires_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
